    async getPlatformDataByContractType(contract) {
        // For each contract type it is necessary an implementation
        switch (contract.contractType) {
            case CONTRACT_TYPES.PEO: {
                contract.peoContract = await this.getPEOContract(contract.id);

                const profile = await this.db.Profile.findFirst({
                    where: {id: contract.ContractorId},
                    attributes: ['email', 'dob', 'phone'],
                    useMaster: false,
                });

                if (!profile) {
                    throw new HttpError.NotFound('Profile not found');
                }

                return {
                    firstName: contract.peoContract.firstName,
                    lastName: contract.peoContract.lastName,
                    street: contract.peoContract.address,
                    city: contract.peoContract.city,
                    state: contract.peoContract.stateCode,
                    zip: contract.peoContract.zipCode,
                    ...(profile.dob ? {dob: moment(profile.dob).format('YYYY-MM-DD')} : {dob: ''}),
