                },
                attributes: ['id', 'status', 'payrollEventExternalId', 'from', 'to'],
                include: [{model: this.db.Contract, as: 'PEOContract', attributes: [], where: {oid: contractOid}, required: true}],
                order: [['from', 'DESC']],
            });

            const nextPaymentEvent = await this._getNextPaymentEventBasedOnPayslip(lastPayslip, contractOid);
            const calendar = nextPaymentEvent?.payrollCalendar;

            if (calendar) {
                payrollCalendarsByContract.set(contractOid, calendar);
            }
        }
        return payrollCalendarsByContract;
    }

    async _getPEOAndEmploymentInfo(contractOid) {
        const peo = await this.getPEOContractByOid({deelContractOid: contractOid});
